import { describe, expect, it } from "bun:test"
import { deserializePublicKeyNtt } from "../../services/FalconService"

const COEFFICIENT_COUNT = 512
const COEFFICIENT_BITS = 14
const VK_LENGTH = (COEFFICIENT_COUNT * COEFFICIENT_BITS) / 8
const Q = 12289

const pack14BitCoefficients = (coeffs: ReadonlyArray<number>): Uint8Array => {
  if (coeffs.length !== COEFFICIENT_COUNT) {
    throw new Error("Expected exactly 512 coefficients")
  }

  const output = new Uint8Array(VK_LENGTH)
  let bitPosition = 0

  for (const coefficient of coeffs) {
    if (coefficient < 0 || coefficient >= Q) {
      throw new Error(`Coefficient out of range: ${coefficient}`)
    }

    for (let bit = 0; bit < COEFFICIENT_BITS; bit += 1) {
      const bitValue = (coefficient >> bit) & 1
      if (bitValue === 1) {
        const byteIndex = Math.floor(bitPosition / 8)
        const bitIndex = bitPosition % 8
        output[byteIndex] = output[byteIndex] | (1 << bitIndex)
      }
      bitPosition += 1
    }
  }

  return output
}

const makeCoefficients = (): Int32Array => {
  const coefficients = new Int32Array(COEFFICIENT_COUNT)
  for (let index = 0; index < COEFFICIENT_COUNT; index += 1) {
    if (index === 0) {
      coefficients[index] = 0
    } else if (index === 1) {
      coefficients[index] = 1
    } else if (index === 2) {
      coefficients[index] = Q - 1
    } else {
      coefficients[index] = (index * 73 + 19) % Q
    }
  }
  return coefficients
}

describe("deserializePublicKeyNtt", () => {
  it("decodes 512 packed 14-bit coefficients", () => {
    const expected = makeCoefficients()
    const packed = pack14BitCoefficients(Array.from(expected))

    const decoded = deserializePublicKeyNtt(packed)

    expect(decoded.length).toBe(COEFFICIENT_COUNT)
    expect(Array.from(decoded)).toEqual(Array.from(expected))
  })

  it("rejects malformed verifying key length", () => {
    const malformed = new Uint8Array(VK_LENGTH - 1)

    expect(() => deserializePublicKeyNtt(malformed)).toThrow(
      "Invalid verifying key length",
    )
  })
})

