import { Effect } from "effect"
import { WasmRuntime } from "./WasmRuntime"
import {
  KeygenError,
  SigningError,
  HintGenerationError,
  PackingError,
  VerificationError,
} from "./errors"
import type {
  FalconKeypair,
  FalconSignatureResult,
  PackedPublicKey,
} from "./types"

const COEFFICIENT_COUNT = 512
const COEFFICIENT_BITS = 14
const VK_LENGTH = (COEFFICIENT_COUNT * COEFFICIENT_BITS) / 8

/**
 * Deserialize 512 packed 14-bit NTT coefficients from a verifying key byte array.
 *
 * Each Zq coefficient is stored in 14 bits (LSB first), giving
 * 512 × 14 = 7168 bits = 896 bytes total.
 */
export function deserializePublicKeyNtt(vkBytes: Uint8Array): Int32Array {
  if (vkBytes.length !== VK_LENGTH) {
    throw new Error(
      `Invalid verifying key length: expected ${VK_LENGTH}, got ${vkBytes.length}`,
    )
  }

  const out = new Int32Array(COEFFICIENT_COUNT)
  for (let i = 0; i < COEFFICIENT_COUNT; i++) {
