const PUBLIC_KEY_BYTES = (PUBLIC_KEY_COEFFICIENTS * PUBLIC_KEY_BITS) / 8
const PUBLIC_KEY_MASK = (1 << PUBLIC_KEY_BITS) - 1
const MODULUS_Q = 12289

export const deserializePublicKeyNtt = (
  verifyingKey: Uint8Array,
): Int32Array => {
  if (verifyingKey.length !== PUBLIC_KEY_BYTES) {
    throw new Error(
      `Invalid verifying key length: expected ${PUBLIC_KEY_BYTES}, got ${verifyingKey.length}`,
    )
  }

  const coefficients = new Int32Array(PUBLIC_KEY_COEFFICIENTS)
  let bitBuffer = 0
  let bitsInBuffer = 0
  let byteIndex = 0

  for (let coefficientIndex = 0; coefficientIndex < PUBLIC_KEY_COEFFICIENTS; coefficientIndex += 1) {
    while (bitsInBuffer < PUBLIC_KEY_BITS) {
      bitBuffer |= verifyingKey[byteIndex] << bitsInBuffer
      bitsInBuffer += 8
      byteIndex += 1
    }

    const coefficient = bitBuffer & PUBLIC_KEY_MASK
    bitBuffer = bitBuffer >>> PUBLIC_KEY_BITS
    bitsInBuffer -= PUBLIC_KEY_BITS

    if (coefficient >= MODULUS_Q) {
      throw new Error(
        `Invalid verifying key coefficient at index ${coefficientIndex}: ${coefficient}`,
      )
    }

    coefficients[coefficientIndex] = coefficient
  }

  return coefficients
}

export class FalconService extends Effect.Service<FalconService>()(
  "FalconService",
  {
    accessors: true,
    // No pre-bundled dependencies: callers must provide WasmRuntime via Layer.
    // This enables unit tests to inject a mock WasmRuntime without the live
    // loader trying to fetch /wasm/falcon_rs.js at import time.
    effect: Effect.gen(function* () {
      const wasm = yield* WasmRuntime

      const generateKeypair = Effect.fn("Falcon.generateKeypair")(
        function* (seed?: Uint8Array) {
          const s =
            seed ?? crypto.getRandomValues(new Uint8Array(32))
          return yield* Effect.try({
            try: () => {
              const result = wasm.keygen(s)
              return {
                secretKey: result.sk,
                verifyingKey: result.vk,
                publicKeyNtt: deserializePublicKeyNtt(result.vk),
              } satisfies FalconKeypair
            },
            catch: (error) =>
              new KeygenError({ message: String(error) }),
          })
        },
      )

      const sign = Effect.fn("Falcon.sign")(
        function* (
          secretKey: Uint8Array,
          message: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () =>
              wasm.sign(secretKey, message, new Uint8Array(0)),
            catch: (error) =>
              new SigningError({ message: String(error) }),
          })
        },
      )

      const verify = Effect.fn("Falcon.verify")(
        function* (
          verifyingKey: Uint8Array,
          message: Uint8Array,
          signature: Uint8Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.verify(verifyingKey, message, signature),
            catch: (error) =>
              new VerificationError({
                message: String(error),
                step: "verify",
              }),
          })
        },
      )

      const createHint = Effect.fn("Falcon.createHint")(
        function* (
          s1: Int32Array,
          pkNtt: Int32Array,
        ) {
          return yield* Effect.try({
            try: () => wasm.create_verification_hint(s1, pkNtt),
            catch: (error) =>
              new HintGenerationError({ message: String(error) }),
          })
        },
      )

      const packPublicKey = Effect.fn("Falcon.packPublicKey")(
        function* (
          pkNtt: Uint16Array,
        ) {
          const slots = yield* Effect.try({
            try: () => wasm.pack_public_key_wasm(pkNtt),
            catch: (error) =>
              new PackingError({ message: String(error) }),
          })
          return { slots } satisfies PackedPublicKey
        },
      )

      return {
        generateKeypair,
        sign,
        verify,
        createHint,
        packPublicKey,
      }
    }),
  },
) {}

